def trap(height):
    l, r = 0, len(height)-1
    lmax, rmax, res = 0, 0, 0
    while l < r:
        if height[l] < height[r]:
            if height[l] >= lmax: lmax = height[l]
            else: res += lmax - height[l]
            l += 1
        else:
            if height[r] >= rmax: rmax = height[r]
            else: res += rmax - height[r]
            r -= 1
    return res

